external_knowledge:
- 'sown the seeds of prosperity' metaphorically refers to farming activities that generate high crop yields;
- 'yielding more than a thousand units of crops at the highest grade' means the yield amount is greater than 1000 and the yield quality is 'High';
- 'fertile grounds' refers to the sites where crops are grown;
- 'number of visits' refers to the count of access events recorded in the access logs.

sql:
SELECT SUM(yield_amount) AS total_yield_amount
FROM crop_yields
WHERE site_id = 1 AND crop_id = 1;

SELECT DISTINCT c.crop_resistance
FROM crops c
JOIN crop_yields cy ON c.crop_id = cy.crop_id;

SELECT site_id, crop_id, SUM(yield_amount) AS total_yield_amount
FROM crop_yields
GROUP BY site_id, crop_id;

SELECT ur.user_name, ur.email, al.access_type
FROM user_roles ur
INNER JOIN access_logs al ON ur.user_id = al.user_id;

SELECT AVG(yield_amount) AS average_yield
FROM crop_yields
WHERE yield_quality = 'High' AND yield_market_price > 1000;

SELECT farmers.farmer_name, sites.site_id
FROM farmers
JOIN sites ON farmers.farmer_id = sites.farmer_id
WHERE sites.site_area = (
    SELECT MAX(site_area) FROM sites
);
